"use strict";(globalThis.webpackChunkdocs=globalThis.webpackChunkdocs||[]).push([[72965],{50796(e){e.exports=JSON.parse('{"tag":{"label":"analyzers","permalink":"/regis/docs/tags/concepts/analyzers","description":"Core concept of extracting data using pluggable analyzers.","allTagsPath":"/regis/docs/tags","count":15,"items":[{"id":"usage/configuration","title":"Advanced Configuration","description":"For more complex projects, regis can be configured using a dedicated YAML file or environment variables.","permalink":"/regis/docs/usage/configuration"},{"id":"concepts/analyzers","title":"Analyzers","description":"regis uses a pluggable architecture where separate Analyzers are responsible for extracting specific types of data from container images or their build artifacts.","permalink":"/regis/docs/concepts/analyzers"},{"id":"reference/analyzers/dockle","title":"dockle","description":"The dockle analyzer is a container image linter that checks for security issues and best practices using Dockle.","permalink":"/regis/docs/reference/analyzers/dockle"},{"id":"reference/analyzers/endoflife","title":"endoflife","description":"The endoflife analyzer checks the support status of the software in the image using the endoflife.date API.","permalink":"/regis/docs/reference/analyzers/endoflife"},{"id":"reference/analyzers/freshness","title":"freshness","description":"The freshness analyzer tracks the age of a container image and compares it to the latest version.","permalink":"/regis/docs/reference/analyzers/freshness"},{"id":"reference/analyzers/hadolint","title":"hadolint","description":"The hadolint analyzer lints a \\"pseudo-Dockerfile\\" reverse-engineered from the image history using Hadolint.","permalink":"/regis/docs/reference/analyzers/hadolint"},{"id":"usage/analyze-image","title":"Image Analysis","description":"You can analyze any public container image. By default, regis produces a JSON report on stdout.","permalink":"/regis/docs/usage/analyze-image"},{"id":"reference/analyzers/popularity","title":"popularity","description":"The popularity analyzer provides community adoption metrics from public registries.","permalink":"/regis/docs/reference/analyzers/popularity"},{"id":"reference/analyzers/provenance","title":"provenance","description":"The provenance analyzer checks for SLSA (Supply-chain Levels for Software Artifacts) provenance and build attestations.","permalink":"/regis/docs/reference/analyzers/provenance"},{"id":"reference/analyzers/sbom","title":"sbom","description":"The sbom analyzer generates a Software Bill of Materials (SBOM) for container images using Trivy.","permalink":"/regis/docs/reference/analyzers/sbom"},{"id":"reference/analyzers/scorecarddev","title":"scorecarddev","description":"The scorecarddev analyzer fetches OpenSSF Scorecard security assessments for the image source repository.","permalink":"/regis/docs/reference/analyzers/scorecarddev"},{"id":"reference/analyzers/size","title":"size","description":"The size analyzer provides a detailed breakdown of an image\'s compressed size.","permalink":"/regis/docs/reference/analyzers/size"},{"id":"reference/analyzers/skopeo","title":"skopeo","description":"The skopeo analyzer fetches image metadata and platform details using the Skopeo CLI.","permalink":"/regis/docs/reference/analyzers/skopeo"},{"id":"reference/analyzers/trivy","title":"trivy","description":"The trivy analyzer scans container images for vulnerabilities and secrets using the Trivy CLI.","permalink":"/regis/docs/reference/analyzers/trivy"},{"id":"reference/analyzers/versioning","title":"versioning","description":"The versioning analyzer detects and classifies the tag naming patterns used by a repository.","permalink":"/regis/docs/reference/analyzers/versioning"}],"unlisted":false}}')}}]);